import json
from chimerax.atomic import AtomicStructure

models = [m for m in session.models if isinstance(m, AtomicStructure)]
rows = []
for model in models:
    chain_count = len(model.chains)
    rows.append([f"#{model.id_string}", model.name, model.num_atoms, model.num_residues, chain_count])

atom_count = sum(row[2] for row in rows)
residue_count = sum(row[3] for row in rows)
payload = {
    "title": "ChimeraX structure summary",
    "subtitle": "Generated from a runscript Python recipe",
    "blocks": [
        {
            "type": "cards",
            "items": [
                {"label": "Models", "value": len(rows)},
                {"label": "Atoms", "value": atom_count},
                {"label": "Residues", "value": residue_count},
            ],
        },
        {
            "type": "table",
            "title": "Open atomic models",
            "columns": ["Model", "Name", "Atoms", "Residues", "Chains"],
            "rows": rows,
        },
    ],
}
session.logger.info("CHIMERAX_MCP_RESULT_JSON=" + json.dumps(payload, ensure_ascii=False))

import json
from chimerax.atomic import AtomicStructure

chain_id_1, residue_number_1 = "A", 10
chain_id_2, residue_number_2 = "A", 50
model = next((m for m in session.models if isinstance(m, AtomicStructure)), None)
if model is None:
    raise RuntimeError("No atomic structure is open")

def find_ca(chain_id, residue_number):
    for residue in model.residues:
        if residue.chain_id == chain_id and residue.number == residue_number:
            for atom in residue.atoms:
                if atom.name == "CA":
                    return atom
    raise RuntimeError(f"CA atom not found for {chain_id}:{residue_number}")

a1 = find_ca(chain_id_1, residue_number_1)
a2 = find_ca(chain_id_2, residue_number_2)
distance = float(((a1.coord - a2.coord) ** 2).sum() ** 0.5)
payload = {
    "model": f"#{model.id_string}",
    "atom_1": str(a1),
    "atom_2": str(a2),
    "distance_angstrom": distance,
}
session.logger.info("CHIMERAX_MCP_RESULT_JSON=" + json.dumps(payload, ensure_ascii=False))

import json
from chimerax.atomic import all_atoms, selected_atoms

cutoff = 4.0
selected = selected_atoms(session)
if len(selected) == 0:
    raise RuntimeError("Select one or more atoms before running this recipe")
nearby = {}
cutoff2 = cutoff * cutoff
for atom in all_atoms(session):
    if atom in selected:
        continue
    for selected_atom in selected:
        if float(((atom.coord - selected_atom.coord) ** 2).sum()) <= cutoff2:
            nearby[str(atom.residue)] = atom.residue
            break

residue_names = sorted(nearby)
payload = {
    "cutoff_angstrom": cutoff,
    "selected_atoms": len(selected),
    "nearby_residue_count": len(residue_names),
    "nearby_residues": residue_names[:100],
    "truncated": len(residue_names) > 100,
}
session.logger.info("CHIMERAX_MCP_RESULT_JSON=" + json.dumps(payload, ensure_ascii=False))

