    session.logger.error(traceback.format_exc())
    payload = {
        "status": "error",
        "error_type": type(exc).__name__,
        "message": str(exc),
    }

session.logger.info("CHIMERAX_MCP_RESULT_JSON=" + json.dumps(payload, ensure_ascii=False))
